/* ============================================================
   DISCOVER NEW UK TRAVEL COMPANIES
   - Reads already-seen domains from Google Sheets (passed in as
     $input items) so we never re-process the same company.
   - Queries SerpAPI with 25+ rotating UK travel searches.
   - Returns only companies NOT already in the sheet.
   Env: SERPAPI_KEY
   ============================================================ */
const serpApiKey = $env.SERPAPI_KEY || '';

// Build set of already-seen domains from the Google Sheet rows
const existingItems = $input.all();
const seenDomains = new Set(
  existingItems
    .map(item => (item.json['Domain'] || item.json['domain'] || '').toLowerCase().trim())
    .filter(Boolean)
);

// 25 rotating search queries covering a wide range of UK travel niches
// Using more queries = more unique companies discovered each hour
const searchQueries = [
  'UK travel agency tour operator site:co.uk',
  'UK independent tour operator package holidays',
  'UK travel company luxury beach holidays',
  'UK adventure travel company tours',
  'UK group travel holidays operator site:co.uk',
  'UK family holiday travel company',
  'UK coach holiday company tours site:co.uk',
  'UK ski snowboard holiday specialist',
  'UK walking trekking hiking holiday company',
  'UK cruise holiday specialist operator',
  'UK honeymoon travel company specialist',
  'UK safari Africa holiday operator',
  'UK beach resort holiday specialist',
  'UK city break short break travel company',
  'UK cultural heritage tours travel operator',
  'London specialist travel agency holidays',
  'Manchester travel agency tour operator',
  'Scotland Highland tours travel company',
  'Wales holiday tours travel operator',
  'Yorkshire Dales holiday travel company',
  'UK solo travel holiday specialist',
  'UK sustainable eco green travel company',
  'UK golf holiday specialist operator',
  'UK spa wellness retreat holiday company',
  'UK bespoke tailor-made holiday travel agent',
  'UK river barge canal holiday operator',
  'UK cycling road bike holiday company',
  'UK horse riding equestrian holiday operator',
  'UK diving snorkelling holiday specialist',
  'UK photography wildlife holiday company'
];

const skipPatterns = [
  'tripadvisor', 'trustpilot', 'google', 'facebook', 'wikipedia',
  'yelp', 'indeed', 'linkedin', 'twitter', 'instagram', 'youtube',
  'booking.com', 'expedia', 'airbnb', 'loveholidays', 'on-the-beach',
  'jet2.', 'tui.', 'firstchoice.', 'easyjet', 'ryanair', 'thomascook',
  'lastminute', 'kayak', 'skyscanner', 'holidaypirates', 'dealchecker',
  'gov.uk', 'bbc.co.uk', 'theguardian', 'telegraph', 'dailymail'
];

const companies = [];
const seenThisRun = new Set();

if (serpApiKey) {
  // Process all queries (30 queries × 20 results = up to 600 candidates)
  for (const query of searchQueries) {
    try {
      const url = [
        'https://serpapi.com/search',
        `?api_key=${encodeURIComponent(serpApiKey)}`,
        '&engine=google',
        `&q=${encodeURIComponent(query)}`,
        '&num=20',
        '&gl=uk',
        '&hl=en',
      ].join('');

      const res = await fetch(url, { signal: AbortSignal.timeout(15000) });
      if (!res.ok) continue;
      const data = await res.json();

      for (const result of (data.organic_results || [])) {
        try {
          const link = result.link || '';
          if (!link.startsWith('http')) continue;
          const hostname = new URL(link).hostname.replace(/^www\./, '').toLowerCase();

          // Skip aggregators, OTAs, media sites
          if (skipPatterns.some(p => hostname.includes(p))) continue;
          // Skip already in Google Sheet
          if (seenDomains.has(hostname)) continue;
          // Skip already found this run
          if (seenThisRun.has(hostname)) continue;

          seenThisRun.add(hostname);

          // Extract clean company name from page title
          const rawTitle = result.title || hostname;
          const name = rawTitle
            .split(/ [-–|:] /)[0]
            .replace(/\(.*?\)/g, '')
            .replace(/\s{2,}/g, ' ')
            .trim();

          companies.push({ name, domain: hostname, website: link });
        } catch {}
      }
    } catch {}
  }
} else {
  // No SERPAPI_KEY – use a small seed list so the workflow still runs
  const seedList = [
    { name: 'Inntravel', domain: 'inntravel.co.uk', website: 'https://www.inntravel.co.uk' },
    { name: 'Exodus Travels', domain: 'exodustravels.com', website: 'https://www.exodustravels.com' },
    { name: 'Neilson Holidays', domain: 'neilson.co.uk', website: 'https://www.neilson.co.uk' },
    { name: 'Explore Worldwide', domain: 'explore.co.uk', website: 'https://www.explore.co.uk' },
    { name: 'G Adventures UK', domain: 'gadventures.com', website: 'https://www.gadventures.com' },
  ];
  for (const c of seedList) {
    if (!seenDomains.has(c.domain)) companies.push(c);
  }
}

if (companies.length === 0) {
  // Nothing new this cycle – return a no-op item so the workflow ends cleanly
  return [{ json: { _noNewLeads: true, message: 'All discovered companies already processed.' } }];
}

return companies.map(c => ({ json: c }));

/* ============================================================
   ANALYSE EACH COMPANY

   LEAD CRITERIA (warm outreach profile):
   ✅ NO Meta Pixel on website  → not doing conversion tracking,
      no Meta ad infrastructure in place = they're not running ads
   ✅ No currently ACTIVE Meta ads in the Ad Library
   ✅ Has social media presence (FB / IG / TikTok) with content
      = they have an audience but are not monetising it with paid ads
   Bonus: had ads historically = already understands paid media

   Step 1 – Firecrawl: scrape website, check for pixel, detect social links
   Step 2 – Apify (Meta Ad Library): check active / lapsed ads
   Step 3 – Score and qualify

   Env: FIRECRAWL_API_KEY, APIFY_API_KEY
   ============================================================ */
const company      = $json;
const firecrawlKey = $env.FIRECRAWL_API_KEY || '';
const apifyKey     = $env.APIFY_API_KEY     || '';

// Same Apify actor used by the main app (search/route.ts)
const APIFY_ACTOR_ID = 'ZQyDz7154hrOfrDMK';

// ──────────────────────────────────────────────────────────────
// STEP 1 – Firecrawl website scrape
// ──────────────────────────────────────────────────────────────
let html            = '';
let pageTitle       = '';
let pageDescription = '';
let scrapeSuccess   = false;
let scrapeError     = '';

if (firecrawlKey && company.website) {
  try {
    const fcRes = await fetch('https://api.firecrawl.dev/v1/scrape', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${firecrawlKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        url: company.website,
        formats: ['html'],
        waitFor: 2000,
      }),
      signal: AbortSignal.timeout(35000),
    });
    if (fcRes.ok) {
      const fc = await fcRes.json();
      html            = fc?.data?.html        || '';
      pageTitle       = fc?.data?.metadata?.title       || '';
      pageDescription = fc?.data?.metadata?.description || '';
      scrapeSuccess   = fc?.success === true;
    } else {
      scrapeError = `HTTP ${fcRes.status}`;
    }
  } catch (e) {
    scrapeError = String(e?.message || 'Firecrawl timeout');
  }
}

// ──────────────────────────────────────────────────────────────
// STEP 2 – Check for Meta Pixel (ABSENCE = our opportunity signal)
// ──────────────────────────────────────────────────────────────
const pixelPatterns = [
  /fbq\s*\(\s*['"]init['"]\s*,\s*['"]?(\d{10,16})['"]?/i,
  /"pixelId"\s*:\s*"(\d{10,16})"/i,
  /facebook\.com\/tr\?id=(\d{10,16})/i,
  /'pixel_id'\s*:\s*'(\d{10,16})'/i,
  /fbPixelId[^\d]+(\d{10,16})/i,
];
let pixelId = null;
for (const p of pixelPatterns) {
  const m = html.match(p);
  if (m) { pixelId = m[1]; break; }
}
const hasPixel = !!pixelId;

// ──────────────────────────────────────────────────────────────
// STEP 3 – Social media presence (UGC / content signals)
// Detect links to social profiles in the HTML
// ──────────────────────────────────────────────────────────────
const hasFacebook  = /facebook\.com\/(?!sharer|share|dialog|plugins|photo|event|group)[a-zA-Z0-9./_-]{3,}/.test(html);
const hasInstagram = /instagram\.com\/[a-zA-Z0-9._]{3,}/.test(html);
const hasTiktok    = /tiktok\.com\/@[a-zA-Z0-9._]{2,}/.test(html);
const hasTwitter   = /(?:twitter|x)\.com\/[a-zA-Z0-9_]{3,}/.test(html);
const hasYoutube   = /youtube\.com\/(channel|user|c\/|@)[a-zA-Z0-9_-]{3,}/.test(html);

// Extract Facebook page URL if present (for the sheet)
let facebookUrl = '';
const fbMatch = html.match(/(?:href=["'])(https?:\/\/(?:www\.)?facebook\.com\/(?!sharer|share|dialog|plugins|photo|event|group)[a-zA-Z0-9./_-]{3,})/i);
if (fbMatch) facebookUrl = fbMatch[1];

let instagramUrl = '';
const igMatch = html.match(/(?:href=["'])(https?:\/\/(?:www\.)?instagram\.com\/[a-zA-Z0-9._]{3,})/i);
if (igMatch) instagramUrl = igMatch[1];

// ──────────────────────────────────────────────────────────────
// STEP 4 – Meta Ad Library check via Apify
// ──────────────────────────────────────────────────────────────
let hasActiveAds         = false;
let hasRecentInactiveAds = false;
let totalAdsFound        = 0;
let mostRecentAdDate     = null;
let adSamples            = [];
let adLibraryError       = '';

if (apifyKey) {
  try {
    const libraryUrl = [
      'https://www.facebook.com/ads/library/',
      '?active_status=all',
      '&ad_type=all',
      '&country=GB',
      `&q=${encodeURIComponent(company.name)}`,
      '&search_type=keyword_unordered',
      '&media_type=all',
    ].join('');

    const runRes = await fetch(
      `https://api.apify.com/v2/acts/${APIFY_ACTOR_ID}/runs?waitForFinish=90`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apifyKey}`,
        },
        body: JSON.stringify({ startUrls: [{ url: libraryUrl }], maxResults: 25 }),
        signal: AbortSignal.timeout(100000),
      }
    );

    const runData = await runRes.json().catch(() => ({}));
    if (!runRes.ok || runData?.error) {
      adLibraryError = runData?.error?.message || 'Apify run failed';
    } else {
      const datasetId = runData?.data?.defaultDatasetId;
      if (!datasetId) {
        adLibraryError = 'No Apify dataset ID returned';
      } else {
        const itemsRes = await fetch(
          `https://api.apify.com/v2/datasets/${datasetId}/items?limit=25`,
          { headers: { 'Authorization': `Bearer ${apifyKey}` }, signal: AbortSignal.timeout(20000) }
        );
        const items = await itemsRes.json().catch(() => []);

        if (Array.isArray(items)) {
          totalAdsFound = items.length;
          const twelveMonthsAgo = Date.now() - 365 * 24 * 60 * 60 * 1000;

          for (const ad of items) {
            if (!ad.endDate) hasActiveAds = true;
            const startMs = ad.startDate ? new Date(ad.startDate).getTime() : 0;
            if (startMs > twelveMonthsAgo) hasRecentInactiveAds = true;
            if (!mostRecentAdDate || startMs > new Date(mostRecentAdDate).getTime()) {
              mostRecentAdDate = ad.startDate || null;
            }
          }

          adSamples = items.slice(0, 3).map(ad => ({
            id:          String(ad.adArchiveID || ''),
            pageName:    ad.pageName || '',
            body:        (ad.adCreativeBodies || [])[0] || '',
            status:      ad.adStatus || (ad.endDate ? 'INACTIVE' : 'ACTIVE'),
            startDate:   ad.startDate || null,
            endDate:     ad.endDate   || null,
            platforms:   ad.publisherPlatforms || [],
            snapshotUrl: ad.adSnapshotUrl || '',
          }));
        }
      }
    }
  } catch (e) {
    adLibraryError = String(e?.message || 'Apify error');
  }
}

// ──────────────────────────────────────────────────────────────
// STEP 5 – Lead qualification
//
// PRIMARY SIGNAL: No Meta Pixel on site = company is NOT using
// Meta's tracking infrastructure → very likely NOT running Meta ads
//
// CONFIRMED BY: Ad Library check (no active ads)
//
// SALES ANGLE: They have social presence + audience (FB/IG/UGC)
// but are not monetising it with paid ads. Perfect prospect.
// ──────────────────────────────────────────────────────────────
const hasSocialPresence = hasFacebook || hasInstagram || hasTiktok;
const neitherPixelNorActiveAds = !hasPixel && !hasActiveAds;

// Must have: no pixel AND no active ads AND some social presence
const isQualified = neitherPixelNorActiveAds && hasSocialPresence;

// Score the lead (max 100)
let leadScore = 0;
if (!hasPixel)             leadScore += 40; // Primary signal – no pixel = not using Meta ads
if (!hasActiveAds)         leadScore += 20; // Confirmed not running ads
if (hasSocialPresence)     leadScore += 15; // Has an audience to advertise to
if (hasRecentInactiveAds)  leadScore += 15; // Was advertising recently – warm/lapsed
if (hasFacebook)           leadScore += 4;
if (hasInstagram)          leadScore += 4;
if (hasTiktok)             leadScore += 2;

const reasonParts = [];
if (!hasPixel && scrapeSuccess)             reasonParts.push('No Meta Pixel detected');
if (!hasPixel && !scrapeSuccess)            reasonParts.push('No pixel (scrape inconclusive)');
if (!hasActiveAds)                          reasonParts.push('Not running Meta ads');
if (hasRecentInactiveAds)                   reasonParts.push('Previously ran Meta ads (< 12m ago)');
if (totalAdsFound > 0 && !hasRecentInactiveAds) reasonParts.push(`${totalAdsFound} historical ad(s)`);
if (hasFacebook)                            reasonParts.push('Facebook page linked');
if (hasInstagram)                           reasonParts.push('Instagram linked');
if (hasTiktok)                              reasonParts.push('TikTok linked');

return [{
  json: {
    // Company
    company_name:            company.name,
    domain:                  company.domain,
    website:                 company.website,
    page_title:              pageTitle,
    page_description:        pageDescription,
    // Pixel signal
    has_pixel:               hasPixel,
    pixel_id:                pixelId || '',
    // Social / UGC signals
    has_facebook:            hasFacebook,
    has_instagram:           hasInstagram,
    has_tiktok:              hasTiktok,
    has_twitter:             hasTwitter,
    has_youtube:             hasYoutube,
    facebook_url:            facebookUrl,
    instagram_url:           instagramUrl,
    // Ad Library
    has_active_ads:          hasActiveAds,
    has_recent_inactive_ads: hasRecentInactiveAds,
    total_ads_found:         totalAdsFound,
    most_recent_ad_date:     mostRecentAdDate,
    ad_samples:              adSamples,
    ad_library_error:        adLibraryError,
    // Qualification
    is_qualified:            isQualified,
    lead_score:              leadScore,
    lead_reason:             reasonParts.join(' | ') || 'Does not meet criteria',
    // Debug
    scrape_success:          scrapeSuccess,
    scrape_error:            scrapeError,
    analysed_at:             new Date().toISOString(),
  }
}];
